@implements IAsyncDisposable
@inject IJSRuntime JS

<div @ref="_wrapperElement">
    @ChildContent
</div>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public int TimeoutSeconds { get; set; } = 300;
    [Parameter] public EventCallback OnIdle { get; set; }
    [Parameter] public EventCallback OnActive { get; set; }

    private ElementReference _wrapperElement;
    private IJSObjectReference? _module;
    private DotNetObjectReference<UserActivityTracker>? _dotNetRef;

    private bool _isIdle;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _dotNetRef = DotNetObjectReference.Create(this);
            _module = await JS.InvokeAsync<IJSObjectReference>(
                "import",
                "./_content/sv-293613f03d9548dea0f2c29d6ef8a66d/Components/UserActivityTracker.razor.js");

            await _module.InvokeVoidAsync("initialize", _wrapperElement, _dotNetRef, TimeoutSeconds);
        }
    }

    [JSInvokable]
    public async Task OnIdleTriggered()
    {
        if (_isIdle) return;
        _isIdle = true;
        await OnIdle.InvokeAsync();
    }

    [JSInvokable]
    public async Task OnActiveTriggered()
    {
        if (!_isIdle) return;
        _isIdle = false;
        await OnActive.InvokeAsync();
    }

    public async ValueTask DisposeAsync()
    {
        if (_module is not null)
        {
            try
            {
                await _module.InvokeVoidAsync("dispose");
                await _module.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit may already be gone during prerendering or navigation.
            }
        }

        _dotNetRef?.Dispose();
    }
}

let timer = null;
let dotNetHelper = null;
let wrapper = null;
let isIdle = false;

const events = ["mousemove", "keydown", "click", "scroll"];

function resetTimer() {
    if (isIdle) {
        isIdle = false;
        dotNetHelper.invokeMethodAsync("OnActiveTriggered");
    }
    clearTimeout(timer);
    timer = setTimeout(() => {
        isIdle = true;
        dotNetHelper.invokeMethodAsync("OnIdleTriggered");
    }, timeoutMs);
}

let timeoutMs = 300000;

export function initialize(element, helper, timeoutSeconds) {
    wrapper = element;
    dotNetHelper = helper;
    timeoutMs = timeoutSeconds * 1000;
    isIdle = false;

    events.forEach(evt => wrapper.addEventListener(evt, resetTimer, { passive: true }));

    timer = setTimeout(() => {
        isIdle = true;
        dotNetHelper.invokeMethodAsync("OnIdleTriggered");
    }, timeoutMs);
}

export function dispose() {
    clearTimeout(timer);
    if (wrapper) {
        events.forEach(evt => wrapper.removeEventListener(evt, resetTimer));
    }
    wrapper = null;
    dotNetHelper = null;
}

